async (params, browser) => {
  // Open page
  await browser.open(`${params.recipe_url}`)

  // Wait for content
  await browser.waitForSelector('h1, [class*="recipe-name"]', 15000)

  // Let page render
  await browser.wait(2500)

  // Scroll for more
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(2000)

  // Extract data
  const page_data = await browser.evaluate(`const name = document.querySelector('h1, [class*="recipe-name"]')?.textContent?.trim()||''; const ingredients = Array.from(document.querySelectorAll('[class*="ingredient"], .ingredient-list li, li.ingredient')).map(el=>el.textContent.trim()).filter(Boolean); const nutrients = {}; document.querySelectorAll('tr, [class*="nutrient"]').forEach(el => { const lbl = el.querySelector('td:first-child, [class*="label"]')?.textContent?.trim()?.toLowerCase()||''; const val = el.querySelector('td:last-child, [class*="value"]')?.textContent?.trim()||''; if(lbl&&val&&lbl.length<30) nutrients[lbl]=val; }); const servings = document.body.innerText.match(/(\d+)\s*servings?/i)?.[1]||''; return { name, ingredients, nutrients, servings, url: window.location.href }`)

  return page_data
}
